import { 運筆, 執筆立 } from '../bi.js';
import { 忿怒開臉, 忿怒點睛, 焰髮, 垂埵耳, 頭光 } from '../bujian/index.js';
export const 宮毘羅 = (呼bi) => {
    const bi = 執筆立(呼bi.ctx, 呼bi.R);
    const { A, dim } = bi;
    const 筆 = 運筆(bi);
    const { M, L, C, Qk, S, 骨, 衣, 細, 逸, 陰, 陽 } = 筆;
    頭光(bi, { 心z: 11, 半徑: 15.6, 淡: 0.45 });
    // ── 岩座：稜面之石（神將立岩，不居蓮）────────────────────────────────────
    衣(() => {
        M(-16.5, 99.5);
        L(-12.5, 95.2);
        L(-5.5, 97.0);
        L(2.5, 94.8);
        L(10.0, 96.8);
        L(15.5, 94.9);
        L(18.0, 99.0);
        S();
        M(-16.5, 99.5);
        C(-15.5, 102.5, -12, 104.2, -7, 104.4);
        S();
        M(18.0, 99.0);
        C(17.2, 102.4, 13.5, 104.2, 8, 104.5);
        S();
        M(-7, 104.4);
        Qk(0.5, 105.2, 8, 104.5);
        S();
        細(() => {
            M(-11.5, 96.2);
            L(-9.0, 100.8);
            S();
            M(4.0, 95.6);
            L(6.2, 100.4);
            S();
            dim(0.7, () => { M(-14.2, 100.6); L(-6.5, 102.2); S(); M(13.8, 100.2); L(6.0, 102.4); S(); });
        });
    });
    // ── 立骨：闊肩短碩之軀（八搩之量）────────────────────────────────────────
    // 頸與斜方肌（怒項粗短）
    骨(() => {
        M(-3.4, 21.2);
        Qk(-3.9, 22.6, -4.0, 24.0);
        S();
        M(3.4, 21.2);
        Qk(3.9, 22.6, 4.0, 24.0);
        S();
        for (const d of [-1, 1]) {
            M(d * 4.0, 24.0);
            C(d * 7.5, 24.0, d * 11.5, 24.8, d * 14.2, 26.4);
            S();
        }
    });
    // ── 尊右臂：高舉仗刀（刀先落，拳覆柄）────────────────────────────────────
    // 太刀：直身微反，鋒上——自拳上出
    衣(() => {
        M(-13.1, 8.2);
        C(-12.4, 2.6, -11.5, -3.0, -10.4, -8.2);
        S();
        M(-14.1, 8.1);
        C(-13.5, 2.6, -12.7, -3.0, -11.6, -8.4);
        S();
        逸(() => { M(-10.4, -8.2); Qk(-10.7, -9.6, -11.6, -8.4); S(); });
        細(() => { M(-13.4, 6.4); C(-12.8, 1.4, -12.1, -3.4, -11.2, -7.4); S(); });
        // 鍔：橫一段
        M(-14.8, 9.1);
        Qk(-13.6, 8.3, -12.4, 9.0);
        S();
        M(-14.8, 9.9);
        Qk(-13.6, 9.2, -12.4, 9.8);
        S();
    });
    // 上臂外揚，前臂上舉；拳握柄
    骨(() => 陽(() => {
        M(-14.2, 26.4);
        C(-16.4, 24.8, -18.0, 22.6, -18.6, 20.0);
        S();
        M(-9.5, 27.6);
        C(-11.6, 26.4, -13.2, 24.6, -14.0, 22.6);
        S();
        M(-18.4, 19.4);
        C(-17.6, 16.4, -16.4, 13.8, -15.0, 11.8);
        S();
        M(-14.0, 21.6);
        C(-13.6, 19.2, -13.4, 16.8, -13.6, 14.6);
        S();
    }));
    衣(() => {
        // 拳握柄（側觀簡拳：郭與三稜，蔽以斷柄）
        const { ctx, u, Y } = bi;
        ctx.save();
        ctx.globalCompositeOperation = 'destination-out';
        ctx.beginPath();
        ctx.moveTo(-16.0 * u, Y(10.6));
        ctx.lineTo(-12.0 * u, Y(10.2));
        ctx.lineTo(-11.6 * u, Y(13.6));
        ctx.lineTo(-15.6 * u, Y(14.0));
        ctx.closePath();
        ctx.fill();
        ctx.restore();
        M(-15.9, 10.9);
        C(-16.3, 12.2, -15.9, 13.5, -14.7, 13.9);
        C(-13.3, 14.3, -12.0, 13.7, -11.9, 12.4);
        Qk(-11.9, 11.2, -12.8, 10.6);
        Qk(-14.4, 10.1, -15.9, 10.9);
        S();
        細(() => {
            for (const t of [0, 1, 2]) {
                M(-15.2 + t * 1.05, 10.7 + t * 0.1);
                Qk(-15.45 + t * 1.05, 11.6, -15.1 + t * 1.05, 12.6 + t * 0.1);
                S();
            }
        });
    });
    // ── 尊左臂：叉腰（肘外張，拳按胯）─────────────────────────────────────────
    骨(() => 陰(() => {
        M(14.2, 26.4);
        C(16.6, 28.2, 18.2, 30.8, 18.4, 33.8);
        S();
        M(9.8, 27.8);
        C(11.8, 29.2, 13.2, 31.2, 13.8, 33.4);
        S();
        M(18.3, 34.4);
        C(17.4, 37.4, 15.6, 40.0, 13.2, 41.8);
        S();
        M(13.6, 34.2);
        C(13.2, 36.4, 12.2, 38.4, 10.8, 40.0);
        S();
    }));
    衣(() => {
        M(11.4, 40.6);
        C(12.4, 41.6, 12.6, 43.0, 11.7, 44.0);
        C(10.7, 45.0, 9.1, 45.0, 8.3, 44.0);
        Qk(7.7, 43.0, 8.3, 41.9);
        Qk(9.6, 40.3, 11.4, 40.6);
        S();
        細(() => {
            for (const t of [0, 1, 2]) {
                M(8.7 + t * 0.95, 41.5 + t * 0.35);
                Qk(8.3 + t * 0.95, 42.3 + t * 0.3, 8.8 + t * 0.95, 43.2 + t * 0.3);
                S();
            }
        });
    });
    // ── 甲冑：肩甲・胸甲札紋・腰帶・腹甲垂片・戰裙 ───────────────────────────
    衣(() => {
        // 肩甲二（覆碗形，緣一重）
        for (const d of [-1, 1]) {
            M(d * 6.8, 26.2);
            C(d * 9.6, 24.6, d * 13.4, 25.2, d * 15.0, 27.6);
            Qk(d * 15.8, 29.0, d * 15.2, 30.6);
            S();
            細(() => { M(d * 7.6, 27.4); C(d * 9.8, 26.2, d * 12.8, 26.6, d * 14.2, 28.6); S(); });
        }
        // 胸甲郭：闊胸束腰
        陽(() => { M(-9.5, 28.0); C(-9.9, 32.6, -9.4, 38.0, -8.4, 43.4); S(); });
        陰(() => { M(9.5, 28.0); C(9.9, 32.6, 9.4, 38.0, 8.4, 43.4); S(); });
        // 領口與胸束
        M(-4.0, 26.2);
        Qk(0, 27.6, 4.0, 26.2);
        S();
        細(() => {
            // 札紋三段（橫界豎綴）
            for (const t of [31.5, 35.5, 39.5]) {
                M(-9.2 + (t - 31.5) * 0.1, t);
                Qk(0, t + 1.0, 9.2 - (t - 31.5) * 0.1, t);
                S();
            }
            for (const t of [32.6, 36.6, 40.4]) {
                for (const fx of [-6.8, -4.1, -1.4, 1.4, 4.1, 6.8]) {
                    M(fx, t);
                    L(fx, t + 2.0);
                    S();
                }
            }
            M(0, 27.8);
            L(0, 43.2);
            S();
            // 胸環二（帶具）
            A(-4.6, 29.8, 0.75);
            A(4.6, 29.8, 0.75);
        });
        // 腰帶與帶扣
        M(-8.5, 43.6);
        Qk(0, 42.8, 8.5, 43.6);
        S();
        M(-8.3, 45.8);
        Qk(0, 45.0, 8.3, 45.8);
        S();
        A(0, 44.4, 0.85);
        細(() => A(0, 44.4, 0.45));
        // 腹甲垂片（蔽膝）：中垂一舌
        M(-2.8, 46.2);
        C(-3.2, 50.0, -2.8, 53.6, -1.8, 56.4);
        S();
        M(2.8, 46.2);
        C(3.2, 50.0, 2.8, 53.6, 1.8, 56.4);
        S();
        M(-1.8, 56.4);
        Qk(0, 57.4, 1.8, 56.4);
        S();
        細(() => { M(-2.2, 49.4); Qk(0, 50.2, 2.2, 49.4); S(); M(-2.0, 52.6); Qk(0, 53.4, 2.0, 52.6); S(); });
        // 戰裙：條片五向，垂至股半
        for (const [bx, sway] of [[-7.2, -0.8], [-4.0, -0.4], [3.6, 0.4], [6.9, 0.8]]) {
            M(bx, 46.4);
            C(bx + sway * 0.4, 50.4, bx + sway, 54.4, bx + sway * 1.4, 58.4);
            S();
        }
        細(() => {
            for (const [bx, sway] of [[-5.6, -0.6], [5.3, 0.6]]) {
                M(bx, 46.6);
                C(bx + sway * 0.4, 50.4, bx + sway * 0.8, 54.0, bx + sway * 1.2, 57.6);
                S();
            }
            M(-8.0, 58.6);
            Qk(-4.2, 60.0, -0.8, 58.9);
            S();
            M(8.0, 58.9);
            Qk(4.2, 60.3, 0.8, 59.2);
            S();
        });
    });
    // ── 腿與脛甲：短碩之股，脛甲直筒，足踏岩 ─────────────────────────────────
    骨(() => {
        陽(() => { M(-7.8, 58.8); C(-8.6, 63.2, -8.8, 67.6, -8.4, 71.6); S(); });
        陰(() => { M(7.8, 58.8); C(8.6, 63.2, 8.8, 67.6, 8.4, 71.6); S(); });
        M(-3.1, 59.6);
        C(-2.8, 63.4, -2.9, 67.0, -3.3, 70.4);
        S();
        M(3.1, 59.6);
        C(2.8, 63.4, 2.9, 67.0, 3.3, 70.4);
        S();
    });
    衣(() => {
        // 膝甲圓盤
        A(-5.8, 72.6, 1.9);
        A(5.8, 72.6, 1.9);
        細(() => { A(-5.8, 72.6, 1.0); A(5.8, 72.6, 1.0); });
        // 脛甲直筒（雙緣中稜）
        for (const d of [-1, 1]) {
            M(d * 7.9, 74.4);
            C(d * 8.2, 80.0, d * 8.0, 86.0, d * 7.4, 91.2);
            S();
            M(d * 3.6, 74.6);
            C(d * 3.4, 80.0, d * 3.6, 86.0, d * 4.1, 91.2);
            S();
            細(() => { M(d * 5.8, 74.8); L(d * 5.8, 91.0); S(); });
        }
        // 足（履簡）：外撇踏岩
        for (const d of [-1, 1]) {
            M(d * 3.9, 91.6);
            Qk(d * 3.4, 93.8, d * 4.4, 95.4);
            S();
            M(d * 7.5, 91.6);
            C(d * 8.7, 92.8, d * 9.9, 94.2, d * 10.6, 95.4);
            S();
            M(d * 4.4, 95.4);
            Qk(d * 7.5, 96.3, d * 10.6, 95.4);
            S();
            細(() => { M(d * 5.0, 93.6); Qk(d * 6.6, 94.2, d * 8.2, 93.8); S(); });
        }
    });
    // ── 頭面：忿怒之制（簡忿）＋亥冠小識 ─────────────────────────────────────
    忿怒開臉(bi);
    焰髮(bi);
    垂埵耳(bi);
    // 頸二道（怒項短，二道足矣）
    細(() => {
        M(-2.4, 21.0);
        Qk(0, 21.7, 2.4, 21.0);
        S();
        dim(0.8, () => { M(-2.9, 22.4); Qk(0, 23.2, 2.9, 22.4); S(); });
    });
    // 亥冠小識：額上獸首簡形（十二支主採一系〔待核〕）——一吻二耳
    細(() => dim(0.8, () => {
        M(-1.1, 8.9);
        Qk(0, 8.1, 1.1, 8.9);
        S();
        M(-0.55, 8.35);
        Qk(0, 8.7, 0.55, 8.35);
        S();
        M(-1.15, 8.75);
        L(-1.6, 7.9);
        S();
        M(1.15, 8.75);
        L(1.6, 7.9);
        S();
    }));
    // ── 忿怒點睛殿後 ──────────────────────────────────────────────────────────
    忿怒點睛(bi);
};
